/**
 * Input validation helpers for API endpoints.
 *
 * Each validate* function returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

// Covers the vast majority of valid email addresses while staying simple.
// RFC 5321 / 5322 allow many edge cases; this regex handles real-world usage.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a route / query parameter that should be a numeric ID.
 * Accepts the raw string value from req.params or req.query.
 *
 * @param {*} id - Value to validate.
 * @returns {string[]} Array of error messages (empty = valid).
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }

  if (!/^\d+$/.test(String(id)) || !Number.isFinite(Number(id))) {
    errors.push('id must be a numeric value');
  }

  return errors;
}

/**
 * Validate a `name` field.
 *
 * Rules:
 *   - Required when `required` is true (default).
 *   - Must be a string.
 *   - Length: 1–100 characters.
 *
 * @param {*}       name     - Value to validate.
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]}
 */
function validateName(name, required = true) {
  const errors = [];

  if (name === undefined || name === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors; // length checks are meaningless on non-strings
  }

  if (name.length < 1) {
    errors.push('name must be at least 1 character long');
  }

  if (name.length > 100) {
    errors.push('name must be at most 100 characters long');
  }

  return errors;
}

/**
 * Validate an `email` field.
 *
 * Rules:
 *   - Required when `required` is true (default).
 *   - Must be a string.
 *   - Must match a valid email format.
 *   - Maximum 254 characters (RFC 5321 limit).
 *
 * @param {*}       email    - Value to validate.
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]}
 */
function validateEmail(email, required = true) {
  const errors = [];

  if (email === undefined || email === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors; // format / length checks are meaningless on non-strings
  }

  if (email.length > 254) {
    errors.push('email must be at most 254 characters long');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the request body for creating a new user.
 * Both `name` and `email` are required.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
}

/**
 * Validate the request body for updating an existing user.
 * At least one of `name` or `email` must be provided; each present field
 * is validated with the same rules as on creation.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUpdateUser(body) {
  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    return ['at least one field (name, email) must be provided for update'];
  }

  return [
    ...(hasName  ? validateName(body.name,   false) : []),
    ...(hasEmail ? validateEmail(body.email, false) : []),
  ];
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};

