/**
 * Validation helper module.
 *
 * Every validator returns an array of human-readable error strings.
 * An empty array means "no errors found".
 */

'use strict';

// ---------------------------------------------------------------------------
// Individual field validators
// ---------------------------------------------------------------------------

/**
 * Validate a route/query parameter that must be a whole-number id.
 * Accepts a raw string value coming from req.params or req.query.
 *
 * @param {string} raw  - The raw string value to check.
 * @param {string} [field='id'] - Field name used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateId(raw, field = 'id') {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }

  // Must consist solely of digits (no decimals, no signs)
  if (!/^\d+$/.test(String(raw))) {
    errors.push(`"${field}" must be a positive integer, got "${raw}"`);
    return errors;
  }

  const num = Number(raw);
  if (!Number.isInteger(num) || num < 1) {
    errors.push(`"${field}" must be a positive integer, got "${raw}"`);
  }

  return errors;
}

/**
 * Validate a "name" value from a request body.
 *
 * Rules:
 *  - Must be present (non-null, non-undefined, non-empty-string)
 *  - Must be a string
 *  - Length: 1–100 characters (after trimming whitespace)
 *
 * @param {*} value - The value to check.
 * @param {string} [field='name'] - Field name used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string, got ${typeof value}`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(
      `"${field}" must be 100 characters or fewer, got ${trimmed.length}`
    );
  }

  return errors;
}

/**
 * Validate an "email" value from a request body.
 *
 * Rules:
 *  - Must be present (non-null, non-undefined)
 *  - Must be a string
 *  - Must match a standard email format
 *  - Maximum 254 characters (RFC 5321)
 *
 * @param {*} value - The value to check.
 * @param {string} [field='email'] - Field name used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string, got ${typeof value}`);
    return errors;
  }

  // RFC 5321 hard limit
  if (value.length > 254) {
    errors.push(
      `"${field}" must be 254 characters or fewer, got ${value.length}`
    );
  }

  // Basic but practical email regex: local@domain.tld
  const EMAIL_RE =
    /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;

  if (!EMAIL_RE.test(value)) {
    errors.push(`"${field}" must be a valid email address, got "${value}"`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite body validators
// ---------------------------------------------------------------------------

/**
 * Validate a request body that must contain BOTH "name" and "email"
 * (used for POST /users — full creation).
 *
 * @param {object} body - req.body
 * @returns {string[]} Combined array of all validation errors.
 */
function validateCreateUserBody(body) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['Request body must be a JSON object with "name" and "email" fields'];
  }

  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a request body for a full replacement (PUT /users/:id).
 * Same rules as creation — both fields are required.
 *
 * @param {object} body - req.body
 * @returns {string[]} Combined array of all validation errors.
 */
function validateReplaceUserBody(body) {
  return validateCreateUserBody(body);
}

/**
 * Validate a request body for a partial update (PATCH /users/:id).
 * At least one recognised field must be present; only the fields that ARE
 * present are validated.
 *
 * @param {object} body - req.body
 * @returns {string[]} Combined array of all validation errors.
 */
function validatePatchUserBody(body) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return [
      'Request body must be a JSON object containing at least one of: "name", "email"',
    ];
  }

  const errors = [];

  const hasName = Object.prototype.hasOwnProperty.call(body, 'name');
  const hasEmail = Object.prototype.hasOwnProperty.call(body, 'email');

  if (!hasName && !hasEmail) {
    errors.push(
      'Request body must contain at least one updatable field: "name", "email"'
    );
    return errors;
  }

  if (hasName) errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmail(body.email));

  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Return an Express middleware that validates req.params.id and, when
 * provided, runs an additional body-validation function.
 *
 * Usage:
 *   router.post('/users', validate({ body: validateCreateUserBody }), handler)
 *   router.get('/users/:id', validate({ id: true }), handler)
 *
 * Options:
 *   id        {boolean}  - Validate req.params.id when true (default false).
 *   body      {Function} - Body-validation function; receives req.body,
 *                          returns string[].
 *
 * On failure sends:
 *   HTTP 400 { errors: string[] }
 *
 * @param {{ id?: boolean, body?: Function }} [options]
 * @returns {import('express').RequestHandler}
 */
function validate({ id = false, body: bodyValidator = null } = {}) {
  return function validationMiddleware(req, res, next) {
    const errors = [];

    if (id) {
      errors.push(...validateId(req.params.id));
    }

    if (bodyValidator) {
      errors.push(...bodyValidator(req.body));
    }

    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }

    return next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Individual validators (useful for unit-testing or ad-hoc use)
  validateId,
  validateName,
  validateEmail,

  // Composite body validators
  validateCreateUserBody,
  validateReplaceUserBody,
  validatePatchUserBody,

  // Middleware factory
  validate,
};

