/**
 * Validation helper module.
 * Each function returns an array of error message strings.
 * An empty array means all checks passed.
 */

/** Matches a valid email address (RFC 5321 simplified). */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Checks whether a value is a valid positive integer.
 * Accepts both numbers and numeric strings (as produced by Express URL params).
 *
 * @param {*} value
 * @returns {boolean}
 */
function isNumericId(value) {
  return /^\d+$/.test(String(value)) && Number(value) > 0;
}

/**
 * Validates a user ID (typically from req.params.id).
 *
 * Rules:
 *  - Required (non-empty)
 *  - Must be a positive integer
 *
 * @param {*} id
 * @returns {string[]} Array of validation error messages.
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no further checks make sense
  }

  if (!isNumericId(id)) {
    errors.push('id must be a positive numeric value');
  }

  return errors;
}

/**
 * Validates the user-facing body fields: name and email.
 *
 * Rules (name):
 *  - Required when requireAll is true
 *  - Must be a string
 *  - Length 1–100 characters
 *
 * Rules (email):
 *  - Required when requireAll is true
 *  - Must be a string
 *  - Must match email format
 *  - Max 254 characters (RFC 5321)
 *
 * @param {object} body - The request body object.
 * @param {{ requireAll?: boolean }} [options]
 *   requireAll – when true (default), missing fields are reported as errors.
 *   Set to false for partial-update (PATCH) semantics.
 * @returns {string[]} Array of validation error messages.
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];
  const { name, email } = body || {};

  // ── name ──────────────────────────────────────────────────────────────────
  if (name === undefined || name === null) {
    if (requireAll) {
      errors.push('name is required');
    }
  } else {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else if (name.length < 1) {
      errors.push('name must be at least 1 character long');
    } else if (name.length > 100) {
      errors.push('name must be at most 100 characters long');
    }
  }

  // ── email ─────────────────────────────────────────────────────────────────
  if (email === undefined || email === null) {
    if (requireAll) {
      errors.push('email is required');
    }
  } else {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else if (email.length > 254) {
      errors.push('email must be at most 254 characters long');
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address');
    }
  }

  return errors;
}

module.exports = { validateId, validateUserBody };

