/**
 * validation.js — Input validation helpers for API endpoints.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

// ---------------------------------------------------------------------------
// Primitive checkers
// ---------------------------------------------------------------------------

/**
 * Returns true when `value` is a positive integer string or number (e.g. "3", 3).
 * Rejects floats, negative numbers, leading zeros, and non-numeric strings.
 */
function isNumericId(value) {
  const n = Number(value);
  return (
    value !== '' &&
    value !== null &&
    value !== undefined &&
    Number.isInteger(n) &&
    n > 0 &&
    String(n) === String(value)
  );
}

/**
 * Returns true when `value` is a non-empty string that matches a valid
 * email address pattern (RFC 5321 practical subset, max 254 chars).
 */
function isValidEmail(value) {
  if (typeof value !== 'string') return false;
  // local@domain.tld — no consecutive dots, no leading/trailing dots in parts
  const emailRegex =
    /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;
  return value.length <= 254 && emailRegex.test(value);
}

// ---------------------------------------------------------------------------
// Field-level validators (return error message or null)
// ---------------------------------------------------------------------------

function validateIdField(value, fieldName = 'id') {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  if (!isNumericId(value)) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

function validateNameField(value, required = true) {
  if (value === undefined || value === null) {
    return required ? 'name is required' : null;
  }
  if (typeof value !== 'string') return 'name must be a string';
  if (value.trim().length < 1) return 'name must be at least 1 character';
  if (value.length > 100) return 'name must be at most 100 characters';
  return null;
}

function validateEmailField(value, required = true) {
  if (value === undefined || value === null) {
    return required ? 'email is required' : null;
  }
  if (typeof value !== 'string') return 'email must be a string';
  if (value.length > 254) return 'email must be at most 254 characters';
  if (!isValidEmail(value)) return 'email must be a valid email address (e.g. user@example.com)';
  return null;
}

// ---------------------------------------------------------------------------
// Composite validators per endpoint
// ---------------------------------------------------------------------------

/**
 * Validates the :id URL parameter used by GET /users/:id,
 * PUT /users/:id, and DELETE /users/:id.
 */
function validateUserId({ id }) {
  const errors = [];
  const err = validateIdField(id, 'id');
  if (err) errors.push(err);
  return errors;
}

/**
 * Validates the request body for POST /users (create).
 * Both `name` and `email` are required.
 */
function validateCreateUser(body = {}) {
  const errors = [];

  const nameErr = validateNameField(body.name, true);
  if (nameErr) errors.push(nameErr);

  const emailErr = validateEmailField(body.email, true);
  if (emailErr) errors.push(emailErr);

  return errors;
}

/**
 * Validates the request body for PUT /users/:id (update).
 * At least one of `name` or `email` must be present; any field
 * that is provided must pass its type/length/format checks.
 */
function validateUpdateUser(body = {}) {
  const errors = [];
  const { name, email } = body;

  const hasName = name !== undefined && name !== null;
  const hasEmail = email !== undefined && email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name or email) must be provided');
    return errors; // further field checks are moot
  }

  if (hasName) {
    const err = validateNameField(name, false);
    if (err) errors.push(err);
  }

  if (hasEmail) {
    const err = validateEmailField(email, false);
    if (err) errors.push(err);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  isNumericId,
  isValidEmail,
  validateUserId,
  validateCreateUser,
  validateUpdateUser,
};

