/**
 * Validation helper module.
 *
 * Each exported function returns an array of error message strings.
 * An empty array means all validations passed.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Validate a user id supplied as a route parameter or query string value.
 * The value arrives as a string from Express; we accept only whole-number strings.
 *
 * @param {string} rawId - The raw string value from req.params / req.query
 * @returns {string[]} Array of validation error messages (empty = valid)
 */
function validateId(rawId) {
  const errors = [];

  if (rawId === undefined || rawId === null || rawId === '') {
    errors.push('id is required');
    return errors;
  }

  if (!/^\d+$/.test(String(rawId)) || Number(rawId) <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a name field.
 *
 * @param {*} name - Value from request body
 * @returns {string[]}
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  if (name.length < NAME_MIN) {
    errors.push(`name must be at least ${NAME_MIN} character`);
  }

  if (name.length > NAME_MAX) {
    errors.push(`name must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

/**
 * Validate an email field.
 *
 * @param {*} email - Value from request body
 * @returns {string[]}
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > EMAIL_MAX) {
    errors.push(`email must be at most ${EMAIL_MAX} characters`);
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the full user body (name + email required).
 * Used by POST /users and PUT /users/:id.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a partial user body (only validate fields that are present).
 * Used by PATCH /users/:id where not all fields must be supplied.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validatePartialUserBody(body) {
  const errors = [];

  if (body.name !== undefined) {
    errors.push(...validateName(body.name));
  }

  if (body.email !== undefined) {
    errors.push(...validateEmail(body.email));
  }

  return errors;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validatePartialUserBody,
};

