/**
 * Validation helper module.
 *
 * Each exported function returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

/** Regex that covers the vast majority of valid e-mail addresses (RFC 5321/5322). */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` supplied as a route parameter or query string value.
 * Accepts numeric strings ("42") as well as actual numbers.
 *
 * @param {*} id
 * @returns {string[]} validation errors
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }

  const parsed = Number(id);
  if (!Number.isFinite(parsed) || parsed !== Math.floor(parsed)) {
    errors.push('id must be a numeric integer value');
  } else if (parsed <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a `name` field from a request body.
 *
 * Rules:
 *  - required (must be present and non-empty)
 *  - must be a string
 *  - length: 1–100 characters
 *
 * @param {*} name
 * @returns {string[]} validation errors
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = name.trim();

  if (trimmed.length === 0) {
    errors.push('name must not be empty');
  } else if (trimmed.length > 100) {
    errors.push('name must be 100 characters or fewer');
  }

  return errors;
}

/**
 * Validate an `email` field from a request body.
 *
 * Rules:
 *  - required (must be present and non-empty)
 *  - must be a string
 *  - must match a valid e-mail format
 *  - length: max 254 characters (RFC 5321 limit)
 *
 * @param {*} email
 * @returns {string[]} validation errors
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.trim().length === 0) {
    errors.push('email must not be empty');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must be 254 characters or fewer');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
  }

  return errors;
}

/**
 * Validate a complete user body (name + email).
 *
 * @param {{ name?: unknown, email?: unknown }} body
 * @returns {string[]} all validation errors found
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Build a standardised 400 response object from a list of error strings.
 *
 * @param {string[]} errors
 * @returns {{ error: string, details: string[] }}
 */
function buildValidationError(errors) {
  return {
    error: 'Validation failed',
    details: errors,
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  buildValidationError,
};

