// Validation helper module
// Provides reusable validators for route handlers in app.js.

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Returns true when `value` represents a valid positive integer id.
 * Accepts both number primitives and their string representations
 * (as they arrive from URL parameters).
 */
function isNumericId(value) {
  if (value === undefined || value === null || value === '') return false;
  const num = Number(value);
  return Number.isInteger(num) && num > 0;
}

/**
 * Validates a route-parameter id.
 * Returns an array of error strings (empty = valid).
 *
 * @param {string|number} id
 * @returns {string[]}
 */
function validateId(id) {
  if (!isNumericId(id)) {
    return ["'id' must be a positive integer"];
  }
  return [];
}

/**
 * Validates user body fields (name, email).
 *
 * Rules applied when a field is present:
 *   name  – must be a string, 1–100 characters
 *   email – must be a string, valid email format, max 254 characters
 *
 * @param {object} body            - The parsed request body
 * @param {object} [options]
 * @param {boolean} [options.requireName=false]  - Treat missing name as an error
 * @param {boolean} [options.requireEmail=false] - Treat missing email as an error
 * @returns {string[]} Array of human-readable error messages
 */
function validateUserFields(body, { requireName = false, requireEmail = false } = {}) {
  const errors = [];
  const { name, email } = body || {};

  // ── Required-field checks ──────────────────────────────────────────────────
  if (requireName && (name === undefined || name === null || name === '')) {
    errors.push("'name' is required");
  }
  if (requireEmail && (email === undefined || email === null || email === '')) {
    errors.push("'email' is required");
  }

  // ── name: type + length ────────────────────────────────────────────────────
  if (name !== undefined && name !== null) {
    if (typeof name !== 'string') {
      errors.push("'name' must be a string");
    } else if (name.length < 1 || name.length > 100) {
      errors.push("'name' must be between 1 and 100 characters");
    }
  }

  // ── email: type + format + length ─────────────────────────────────────────
  if (email !== undefined && email !== null) {
    if (typeof email !== 'string') {
      errors.push("'email' must be a string");
    } else if (email.length > 254) {
      errors.push("'email' must be at most 254 characters");
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push("'email' must be a valid email address");
    }
  }

  return errors;
}

/**
 * Sends a standardised 400 Validation Failed response.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationErrors(res, errors) {
  return res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = { validateId, validateUserFields, sendValidationErrors };
